import { Capacitor } from '@capacitor/core';
import { CapacitorSQLite, SQLiteConnection } from '@capacitor-community/sqlite';
import { JeepSqlite } from 'jeep-sqlite/dist/components/jeep-sqlite';
import { SQLiteDBConnection, useSQLite as useSQL } from 'vue-sqlite-hook';

const onProgressImport = async (progress: string) => {
  console.log(progress);
};
const onProgressExport = async (progress: string) => {
  console.log(progress);
};

const mutex = new Mutex();

const initSQL = new Promise(async resolve => {
  try {
    const platform = Capacitor.getPlatform();
    if (platform === 'web') {
      // Create the 'jeep-sqlite' Stencil component
      customElements.define('jeep-sqlite', JeepSqlite);
      const jeepSqlite = document.createElement('jeep-sqlite');
      document.body.appendChild(jeepSqlite);
      await customElements.whenDefined('jeep-sqlite');
      // Initialize the Web store
      const sqlite = new SQLiteConnection(CapacitorSQLite);
      await sqlite.initWebStore();
    }
  } catch (err) {
    console.log(`Error: ${err}`);
    throw new Error(`Error: ${err}`);
  } finally {
    resolve(null);
  }
});

await useSQLite(
  import.meta.env.VITE_DATABASE,
  async db =>
    await db.execute(`
      CREATE TABLE IF NOT EXISTS models (model VARCHAR(24) NOT NULL, key VARCHAR(24) NOT NULL, data TEXT, PRIMARY KEY (model, key));
    `),
);

export async function useSQLite<T>(
  database: string,
  commands: (db: SQLiteDBConnection) => Promise<T>,
) {
  await initSQL;

  const sqlite = useSQL({
    onProgressImport,
    onProgressExport,
  });

  const echoPing = createId();
  const { value: echoPong } = await sqlite.echo(echoPing);
  if (echoPing !== echoPong) {
    throw new Error('SQLite echo failure');
  }

  const release = await mutex.obtain();
  try {
    const db = await sqlite.createConnection(database, false, 'secret', 1);
    await db.open();
    const result = await commands(db);
    await db.close();
    await sqlite.closeConnection(database);
    return result;
  } finally {
    release();
  }
}
