import { Awaitable } from '@vueuse/core';
import { UnwrapRef } from 'vue';

export function computedWith<T, W extends object = object>(
  sources: W,
  callback: () => Awaitable<UnwrapRef<T>>,
  initialValue: T,
) {
  const result = ref(initialValue);
  watch(sources, async () => result.value = await callback(), {
    immediate: true,
  });
  return result;
}
