import { DelayedNotificator } from '~~/utils/delayed-notificator';
import { Relations } from '~~/utils/relations';
import { Tag } from '~~/models/tag';
import { UnwrapRef } from 'vue';

declare global {
  type Type<T> = T;

  // eslint-disable-next-line @typescript-eslint/no-empty-interface
  interface ChecklistItem extends Type<[string, boolean, string, Checklist]> {}
  type Checklist = ChecklistItem[];

  interface ITask {
    id: string;
    predecessors: string[];
    successors: string[];
    tags: string[];
    dateTimeCreated: null | string;
    dateTimeUpdated: null | string;
    dateStart: null | string;
    timeStart: null | string;
    dateEnd: null | string;
    timeEnd: null | string;
    title: string;
    checklist: Checklist;
    isDone: boolean;
    availability: Frequency;
  }
}

export const TaskNotificationBus = new NotificationBus<Task>(
  async (taskId, types) => {
    const task = await taskGet(taskId);
    if (!task) return;

    const actions = [] as Promise<unknown>[];

    if (
      types.some(type =>
        [
          'tags',
          'tags.status',
          'availability',
          'dateStart',
          'dateEnd',
          'timeStart',
          'timeEnd',
          'isDone',
          'predecessors',
          'predecessor.isDone',
          'recalculate.isAvailable',
        ].includes(type),
      )
    ) {
      actions.push(task.refreshIsAvailable());
    }

    if (types.includes('checklist')) {
      if (task.checklistTotal) {
        task.isDone = task.checklistTotal === task.checklistDone;
      }
    }

    await Promise.all(actions);
  },
);

export class Task {
  public isDirty = false;
  public readonly data: ITask;
  public readonly tags: Ref<UnwrapRef<Tag[]>>;

  private constructor(data: Partial<ITask> = {}) {
    this.data = reactive({
      id: data.id ?? createId(),
      predecessors: data.predecessors ?? [],
      successors: data.successors ?? [],
      tags: data.tags ?? [],
      dateTimeCreated: data.dateTimeCreated ?? null,
      dateTimeUpdated: data.dateTimeUpdated ?? null,
      dateStart: data.dateStart ?? null,
      timeStart: data.timeStart ?? null,
      dateEnd: data.dateEnd ?? null,
      timeEnd: data.timeEnd ?? null,
      title: `${data.title}`, // TODO: Replace with data.title ?? ''
      checklist:
        useCloneDeep(
          data.checklist?.map(c => [
            c[0],
            c[1],
            c[2] ?? createId(),
            c[3] ?? [],
          ]),
        ) ?? [],
      isDone: data.isDone ?? false,
      availability: Array.isArray(data.availability)
        ? useCloneDeep((data as unknown as { repeat: Frequency }).repeat) // TODO: Remove
        : useCloneDeep(data.availability) ?? {
            type: FrequencyType.ALWAYS,
          },
    });

    this.tags = computedWith(
      [this.data.tags],
      async () => {
        const storeTag = await useStoreTag();
        let tags: UnwrapRef<Tag>[] = await Promise.all(
          this.data.tags.map(tagGet),
        );
        tags = tags.filter(Boolean);
        tags.sort(
          (a, b) => storeTag.tags.indexOf(a) - storeTag.tags.indexOf(b),
        );
        return tags;
      },
      [],
    );
  }

  public static fromData(data: Partial<ITask>): UnwrapRef<Task> {
    const task = reactive(new Task(data)) as Task & UnwrapRef<Task>;
    task._relations = Relations.create(TaskNotificationBus, task, taskGet);
    task._notificator = new DelayedNotificator(TaskNotificationBus, task);
    return task;
  }

  public static create(id?: string) {
    return Task.fromData({ id, title: '' });
  }

  public static fromTask(task: Task) {
    return Task.fromData(task.data);
  }

  private _relations!: UnwrapRef<Relations<Task>>;
  public get relations() {
    return this._relations;
  }

  private _notificator!: DelayedNotificator<Task>;
  public get notificator() {
    return this._notificator;
  }

  private _isInitialized: symbol | undefined;
  public async init(this: UnwrapRef<Task>) {
    const task = this as UnwrapRef<Task> & Task;
    if (task._isInitialized) return;
    task._isInitialized = Symbol();

    this.isDirty = false;

    this.dateTimeCreated ??= Temporal.Now.plainDateTimeISO();
    this.dateTimeUpdated ??= Temporal.Now.plainDateTimeISO();

    await TaskNotificationBus.emit(this);
  }

  public get id() {
    return this.data.id;
  }

  public get title() {
    return this.data.title;
  }
  public set title(value) {
    this.data.title = value;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'title');
  }

  public get isDone() {
    return this.data.isDone;
  }
  public set isDone(value) {
    this.data.isDone = value;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'isDone');
  }

  public get checklist() {
    return this.data.checklist;
  }
  public set checklist(value) {
    this.data.checklist = value;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'checklist');
  }

  public get checklistTotal() {
    return this.data.checklist.length;
  }

  public get checklistDone() {
    return this.data.checklist.filter(([, isDone]) => isDone).length;
  }

  public get dateTimeCreated() {
    return !this.data.dateTimeCreated
      ? null
      : Temporal.PlainDateTime.from(this.data.dateTimeCreated);
  }
  public set dateTimeCreated(value) {
    this.data.dateTimeCreated = value?.toJSON().slice(0, 19) ?? null;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'dateTimeCreated');
  }

  public get dateTimeUpdated() {
    return !this.data.dateTimeUpdated
      ? null
      : Temporal.PlainDateTime.from(this.data.dateTimeUpdated);
  }
  public set dateTimeUpdated(value) {
    this.data.dateTimeUpdated = value?.toJSON().slice(0, 19) ?? null;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'dateTimeUpdated');
  }

  public get dateStart() {
    return !this.data.dateStart
      ? null
      : Temporal.PlainDate.from(this.data.dateStart);
  }
  public set dateStart(value) {
    this.data.dateStart = value?.toJSON().slice(0, 10) ?? null;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'dateStart');
  }

  public get timeStart() {
    return !this.data.timeStart
      ? null
      : Temporal.PlainTime.from(this.data.timeStart);
  }
  public set timeStart(value) {
    this.data.timeStart = value?.toJSON().slice(0, 5) ?? null;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'timeStart');
  }

  public get dateEnd() {
    return !this.data.dateEnd
      ? null
      : Temporal.PlainDate.from(this.data.dateEnd);
  }
  public set dateEnd(value) {
    this.data.dateEnd = value?.toJSON().slice(0, 10) ?? null;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'dateEnd');
  }

  public get timeEnd() {
    return !this.data.timeEnd
      ? null
      : Temporal.PlainTime.from(this.data.timeEnd);
  }
  public set timeEnd(value) {
    this.data.timeEnd = value?.toJSON().slice(0, 5) ?? null;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'timeEnd');
  }

  public get availability() {
    return this.data.availability;
  }
  public set availability(value) {
    this.data.availability = value;
    this.isDirty = true;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'availability');
  }

  private _isAvailable = false;
  public get isAvailable() {
    return this._isAvailable;
  }
  public set isAvailable(value) {
    this._isAvailable = value;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'isAvailable');
  }

  private _tsSwitchAt = Infinity;
  public get tsSwitchAt() {
    return this._tsSwitchAt;
  }
  public set tsSwitchAt(value) {
    this._tsSwitchAt = value;
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'tsSwitchAt');
  }

  public async refreshIsAvailable(this: UnwrapRef<Task>) {
    if (this.data.isDone) {
      this.isAvailable = false;
      this.tsSwitchAt = Infinity;
      return;
    }

    if (this.tags.length && this.tags.some(tag => !tag.isAvailable)) {
      this.isAvailable = false;
      this.tsSwitchAt = Infinity;
      return;
    }

    const predecessors = await this.relations.predecessors;
    if (predecessors.some(predecessor => !predecessor.isDone)) {
      this.isAvailable = false;
      this.tsSwitchAt = Infinity;
      return;
    }

    refreshAvailability(this, () =>
      this.notificator.notify('recalculate.isAvailable', this.tsSwitchAt),
    );
  }

  public tagAdd(this: UnwrapRef<Task>, tag: UnwrapRef<Tag>) {
    if (this.data.tags.indexOf(tag.id) > -1) return;
    this.data.tags.push(tag.id);
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'tags');
    tag.taskAdd(this);
  }

  public tagRemove(this: UnwrapRef<Task>, tag: UnwrapRef<Tag>) {
    const index = this.data.tags.indexOf(tag.id);
    if (index < 0) return;
    this.data.tags.splice(index, 1);
    TaskNotificationBus.emit(this as UnwrapRef<Task>, 'tags');
    tag.taskRemove(this);
  }
}

export const useTask = useStoreAccessor<UnwrapRef<Task>>(
  new StoreSQLite(import.meta.env.VITE_DATABASE, 'tasks'),
  {
    read: async value => {
      const { data } = JSON.parse(value) as Task;
      return Task.fromData(data);
    },
    write: ({ data }) => JSON.stringify({ data }),
  },
  id => Task.fromData({ id, title: '⚠️ Failed to fetch from DB' }),
  ({ value: task }) => task?.data ?? null,
);

export async function taskGet(id: string) {
  return (await useTask(id)).value;
}

export async function taskSet(task: UnwrapRef<Task>) {
  (await useTask(task.id)).value = task;
}

export async function taskDel(id: string) {
  const refTask = await useTask(id);
  const task = refTask.value;
  await task.relations.detach();
  task.tags.forEach(tag => task.tagRemove(tag));
  refTask.value = undefined as unknown as UnwrapRef<Task>;
}
