import 'temporal-polyfill/global';
import { FrequencyType } from '~~/types/frequency';

const midnight = new Temporal.PlainTime();

function closestInTheFuture(
  now: Temporal.PlainDateTime,
  ...dates: Temporal.PlainDateTime[]
) {
  dates.sort(Temporal.PlainDateTime.compare);
  for (const date of dates) {
    if (Temporal.PlainDateTime.compare(date, now) > 0) {
      return date;
    }
  }
  return null;
}

declare global {
  interface IAvailable {
    isAvailable: boolean;
    tsSwitchAt: number;
    dateStart: Temporal.PlainDate | null;
    dateEnd: Temporal.PlainDate | null;
    timeStart: Temporal.PlainTime | null;
    timeEnd: Temporal.PlainTime | null;
    availability: Frequency;
  }
}

export function refreshAvailability(subject: IAvailable, check: () => void) {
  if (subject.availability.type === FrequencyType.ALWAYS) {
    subject.isAvailable = true;
    subject.tsSwitchAt = Infinity;
    return;
  }
  let msSwitchAfter = null as null | number;
  const now = Temporal.Now.plainDateTimeISO();
  if (subject.dateEnd && Temporal.PlainDate.compare(subject.dateEnd, now) < 0) {
    subject.isAvailable = false;
    msSwitchAfter = null;
  } else if (
    subject.dateStart &&
    Temporal.PlainDate.compare(subject.dateStart, now) > 0
  ) {
    [subject.isAvailable, msSwitchAfter] = [
      false,
      now
        .until(
          subject.dateStart.toPlainDateTime(subject.timeStart ?? undefined),
        )
        .total({ unit: 'milliseconds' }),
    ];
  } else {
    [subject.isAvailable, msSwitchAfter] = fits(
      subject.availability,
      now,
      subject.timeStart ?? undefined,
      subject.timeEnd ?? undefined,
    );
  }

  subject.tsSwitchAt = msSwitchAfter
    ? Temporal.Now.instant().epochMilliseconds + msSwitchAfter
    : Infinity;
  msSwitchAfter && check();
}

export function fits(
  availability: Frequency,
  now: Temporal.PlainDateTime,
  timeStart: Temporal.PlainTime = midnight,
  timeEnd: Temporal.PlainTime = midnight,
): [boolean, number | null] {
  if (availability.type === FrequencyType.ALWAYS) return [true, null];

  const isOvernightTimeFrame =
    Temporal.PlainTime.compare(timeStart, timeEnd) >= 0;

  function fitsTimeFrame(test: (now: Temporal.PlainDateTime) => boolean) {
    const fitsTimeStart = Temporal.PlainTime.compare(timeStart, now) <= 0;
    const fitsTimeEnd = Temporal.PlainTime.compare(now, timeEnd) < 0;
    return isOvernightTimeFrame
      ? fitsTimeStart && test(now) ||
          fitsTimeEnd && test(now.add({ days: -1 }))
      : fitsTimeStart && fitsTimeEnd && test(now);
  }

  switch (availability.type) {
    case FrequencyType.DAILY: {
      const days = [];
      for (let i = 0; i < 2; ++i) {
        days.push(now.withPlainTime(timeStart).add({ days: i }));
        days.push(now.withPlainTime(timeEnd).add({ days: i }));
      }
      const nextDate = closestInTheFuture(
        now,
        ...days,
      ) as Temporal.PlainDateTime;
      const msWaitTime = now.until(nextDate).total({ unit: 'milliseconds' });
      return [fitsTimeFrame(() => true), msWaitTime > 0 ? msWaitTime : null];
    }

    case FrequencyType.ONE_TIME: {
      const day = Temporal.PlainDateTime.from(availability.date);
      const dateTimeStart = day.withPlainTime(timeStart);
      let dateTimeEnd = day.withPlainTime(timeEnd);
      if (isOvernightTimeFrame) {
        dateTimeEnd = dateTimeEnd.add({ days: 1 });
      }
      const nextDate = closestInTheFuture(now, dateTimeStart, dateTimeEnd);
      const msWaitTime = !nextDate
        ? null
        : now.until(nextDate).total({ unit: 'milliseconds' });
      return [
        Temporal.PlainDateTime.compare(now, dateTimeStart) >= 0 &&
          Temporal.PlainDateTime.compare(now, dateTimeEnd) < 0,
        msWaitTime,
      ];
    }

    case FrequencyType.WEEKLY:
      const daysToWeekday = (7 + availability.weekday - now.dayOfWeek) % 7;
      const daysToWeekdayOvernight = daysToWeekday + +isOvernightTimeFrame;
      const days = [
        now.add({ days: daysToWeekdayOvernight - 7 }).withPlainTime(timeEnd),
        now.add({ days: daysToWeekday }).withPlainTime(timeStart),
        now.add({ days: daysToWeekdayOvernight }).withPlainTime(timeEnd),
        now.add({ days: daysToWeekday + 7 }).withPlainTime(timeStart),
      ];
      const nextDate = closestInTheFuture(
        now,
        ...days,
      ) as Temporal.PlainDateTime;
      const msWaitTime = now.until(nextDate).total({ unit: 'milliseconds' });

      return [
        fitsTimeFrame(now => now.dayOfWeek === availability.weekday),
        msWaitTime,
      ];

    case FrequencyType.MONTHLY:
      switch (availability.by) {
        case IntervalUnit.DAY: {
          const daysToDay = (daysInMonth: number) =>
            ((daysInMonth + availability.day - now.day - 1) % daysInMonth +
              1) %
            daysInMonth;
          const daysToDayOvernight = (daysInMonth: number) =>
            daysToDay(daysInMonth) + +isOvernightTimeFrame;
          const daysThisMonth = now.daysInMonth;
          const daysLastMonth = now.add({ months: -1 }).daysInMonth;
          const days = [
            now
              .add({ days: daysToDayOvernight(daysLastMonth) - daysLastMonth })
              .withPlainTime(timeEnd),
            now
              .add({ days: daysToDay(daysThisMonth) })
              .withPlainTime(timeStart),
            now
              .add({ days: daysToDayOvernight(daysThisMonth) })
              .withPlainTime(timeEnd),
            now
              .add({ days: daysToDay(daysThisMonth) + daysThisMonth })
              .withPlainTime(timeStart),
          ].filter(
            day =>
              day.day === availability.day ||
              isOvernightTimeFrame &&
                day.add({ days: -1 }).day === availability.day &&
                Temporal.PlainTime.compare(day, timeEnd) === 0,
          );
          const nextDate = closestInTheFuture(
            now,
            ...days,
          ) as Temporal.PlainDateTime;
          const msWaitTime = now
            .until(nextDate)
            .total({ unit: 'milliseconds' });

          return [
            fitsTimeFrame(now => now.day === availability.day),
            msWaitTime,
          ];
        }

        default:
          const exhaustiveCheck: never = availability.by;
          throw new Error(`Unhandled IntervalUnit: ${exhaustiveCheck}`);

        // case 'Weekday': {
        //   const days = [];
        //   for (let i = 0; i < 2; ++i) {
        //     const firstDayOfMonth = now.with({ day: 1 }).add({ months: i });
        //     const firstWeekdayOfMonth = firstDayOfMonth.dayOfWeek;
        //     let skipDays =
        //       (((7 + availability.weekday - firstWeekdayOfMonth - 1) % 7) + 1) % 7;
        //     switch (availability.order) {
        //       case WeekOrder.FIRST:
        //         skipDays += 0;
        //         break;
        //       case WeekOrder.SECOND:
        //         skipDays += 7;
        //         break;
        //       case WeekOrder.THIRD:
        //         skipDays += 14;
        //         break;
        //       case WeekOrder.FOURTH:
        //         skipDays += 21;
        //         break;
        //       case WeekOrder.FIFTH:
        //         skipDays += 28;
        //         break;
        //     }
        //     const day = firstDayOfMonth.add({ days: skipDays });
        //     if (day.month !== firstDayOfMonth.month) {
        //       continue;
        //     }
        //     days.push(day.withPlainTime(timeStart));
        //     days.push(day.withPlainTime(timeEnd));
        //   }
        //   const nextDate = closestInTheFuture(
        //     now,
        //     ...days,
        //   ) as Temporal.PlainDateTime;
        //   const msWaitTime = now
        //     .until(nextDate)
        //     .total({ unit: 'milliseconds' });
        //   return [
        //     fitsTimeFrame(now => now.dayOfWeek === availability.weekday),
        //     msWaitTime,
        //   ];
        // }
      }

    default:
      const exhaustiveCheck: never = availability;
      throw new Error(`Unhandled Frequency: ${exhaustiveCheck}`);
  }
}
