import { UnwrapRef } from 'vue';
import { NotificationBus } from '~~/utils/notification-bus';

export class Relations<
  T extends {
    id: string;
    isDirty: boolean;
    data: { predecessors: string[]; successors: string[] };
    relations: UnwrapRef<Relations<T>>;
    dateTimeUpdated: null | Temporal.PlainDateTime;
  },
  I = T extends { data: infer I } ? I : never,
  Key extends
    | (string & keyof I)
    | (string & keyof T)
    | `recalculate.${string & keyof T}` =
    | (string & keyof I)
    | (string & keyof T)
    | `recalculate.${string & keyof T}`,
> {
  private constructor(
    private notificationBus: NotificationBus<T, I>,
    private subject: UnwrapRef<T>,
    private subjectGetter: (id: string) => Promise<UnwrapRef<T>>,
  ) {}

  public static create<
    T extends {
      id: string;
      isDirty: boolean;
      data: { predecessors: string[]; successors: string[] };
      relations: UnwrapRef<Relations<T>>;
      dateTimeUpdated: null | Temporal.PlainDateTime;
    },
    I = T extends { data: infer I } ? I : never,
  >(
    notificationBus: NotificationBus<T, I>,
    subject: UnwrapRef<T>,
    subjectGetter: (id: string) => Promise<UnwrapRef<T>>,
  ) {
    return reactive(new Relations(notificationBus, subject, subjectGetter));
  }

  public get predecessors(): Promise<UnwrapRef<T>[]> {
    return Promise.all(this.subject.data.predecessors.map(this.subjectGetter));
  }

  public get successors(): Promise<UnwrapRef<T>[]> {
    return Promise.all(this.subject.data.successors.map(this.subjectGetter));
  }

  private async hasInPredecessors(subjectId: string) {
    for (const predecessorId of this.subject.data.predecessors) {
      if (predecessorId === subjectId) return true;
      const subject = await this.subjectGetter(predecessorId);
      if (
        await (subject.relations as Relations<T, I>).hasInPredecessors(
          subjectId,
        )
      )
        return true;
    }
    return false;
  }

  public async hasInDirectPredecessors(subjectId: string) {
    if (this.subject.id === subjectId) return true;
    for (const predecessorId of this.subject.data.predecessors) {
      const subject = await this.subjectGetter(predecessorId);
      if (
        await (subject.relations as Relations<T, I>).hasInPredecessors(
          subjectId,
        )
      )
        return true;
    }
    return false;
  }

  private async hasInSuccessors(subjectId: string) {
    for (const successorId of this.subject.data.successors) {
      if (successorId === subjectId) return true;
      const subject = await this.subjectGetter(successorId);
      if (
        await (subject.relations as Relations<T, I>).hasInSuccessors(subjectId)
      )
        return true;
    }
    return false;
  }

  public async hasInDirectSuccessors(subjectId: string) {
    if (this.subject.id === subjectId) return true;
    for (const successorId of this.subject.data.successors) {
      const subject = await this.subjectGetter(successorId);
      if (
        await (subject.relations as Relations<T, I>).hasInSuccessors(subjectId)
      )
        return true;
    }
    return false;
  }

  public hasSuccessor(subject: UnwrapRef<T>) {
    return this.subject.data.successors.includes(subject.id);
  }

  public async addSuccessor(subject: UnwrapRef<T>) {
    if (
      !this.hasSuccessor(subject) &&
      !await this.hasInPredecessors(subject.id)
    ) {
      this.subject.data.successors.push(subject.id);
      this.notificationBus.emit(this.subject, 'successors' as Key);
      await subject.relations.addPredecessor(this.subject);
    }
  }

  public async removeSuccessor(subject: UnwrapRef<T>) {
    const index = this.subject.data.successors.indexOf(subject.id);
    if (index > -1) {
      this.subject.data.successors.splice(index, 1);
      this.notificationBus.emit(this.subject, 'successors' as Key);
      await subject.relations.removePredecessor(this.subject);
    }
  }

  public hasPredecessor(subject: UnwrapRef<T>) {
    return this.subject.data.predecessors.includes(subject.id);
  }

  public async addPredecessor(subject: UnwrapRef<T>) {
    if (
      !this.hasPredecessor(subject) &&
      !await this.hasInSuccessors(subject.id)
    ) {
      this.subject.data.predecessors.push(subject.id);
      this.notificationBus.emit(this.subject, 'predecessors' as Key);
      await subject.relations.addSuccessor(this.subject);
    }
  }

  public async removePredecessor(subject: UnwrapRef<T>) {
    const index = this.subject.data.predecessors.indexOf(subject.id);
    if (index > -1) {
      this.subject.data.predecessors.splice(index, 1);
      this.notificationBus.emit(this.subject, 'predecessors' as Key);
      await subject.relations.removeSuccessor(this.subject);
    }
  }

  async detach() {
    for (const subjectId of this.subject.data.predecessors) {
      const subject = await this.subjectGetter(subjectId);
      await this.removePredecessor(subject);
    }
    await Promise.all([
      ...await this.subject.data.predecessors.map(async subjectId => {
        const subject = await this.subjectGetter(subjectId);
        await this.removePredecessor(subject);
      }),
      ...await this.subject.data.successors.map(async subjectId => {
        const subject = await this.subjectGetter(subjectId);
        await this.removeSuccessor(subject);
      }),
    ]);
  }
}
