import { UnwrapRef } from 'vue';
import { Tag } from '~~/models/tag';
import { Mutex } from '~~/utils/mutex';

export const mutexStoreTag = new Mutex();

export async function useStoreTag() {
  let tagIds = $(await getSet('tagIds'));

  return defineStore('tag', () => {
    let isLoaded = $ref(false);
    let tagsVersion = $ref(0);
    let tags: UnwrapRef<Tag>[] = $ref([]);

    const tagsAvailable = $computed(() => tags.filter(tag => tag.isAvailable));

    watch(
      $$(tagsVersion),
      async () => {
        const release = await mutexStoreTag.obtain();
        try {
          tags = await Promise.all([...tagIds].map(tagGet));
          await Promise.all(tags.map(tag => tag.init()));
        } finally {
          release();
          isLoaded = true;
        }
      },
      { immediate: true },
    );

    async function tagSave(tag: UnwrapRef<Tag>, bypass = false) {
      const release = await mutexStoreTag.obtain(bypass);
      try {
        await tagSet(tag);
        tagIds.delete(tag.id); // Make tag appear on the bottom
        tagIds.add(tag.id);
        ++tagsVersion;
      } finally {
        release();
      }
    }

    async function tagDelete(tagId: string, bypass = false) {
      const release = await mutexStoreTag.obtain(bypass);
      try {
        tagIds.delete(tagId);
        await tagDel(tagId);
        ++tagsVersion;
      } finally {
        release();
      }
    }

    const dateNeg = Temporal.PlainDateTime.from('1000-01-01');
    async function sort() {
      const release = await mutexStoreTag.obtain();
      try {
        tagIds = new Set(
          tags
            .sort((a, b) => {
              if (isFinite(a.tsSwitchAt) && isFinite(b.tsSwitchAt)) {
                return (
                  b.tsSwitchAt - a.tsSwitchAt ||
                  Temporal.PlainDateTime.compare(
                    a.dateTimeUpdated ?? dateNeg,
                    b.dateTimeUpdated ?? dateNeg,
                  ) ||
                  +a.isAvailable - +b.isAvailable
                );
              }
              if (isFinite(a.tsSwitchAt)) return 1;
              if (isFinite(b.tsSwitchAt)) return -1;
              return (
                Temporal.PlainDateTime.compare(
                  a.dateTimeUpdated ?? dateNeg,
                  b.dateTimeUpdated ?? dateNeg,
                ) || +a.isAvailable - +b.isAvailable
              );
            })
            .map(tag => tag.id),
        );

        ++tagsVersion;
      } finally {
        release();
      }
    }

    TagNotificationBus.watch('tsSwitchAt', sort);
    TagNotificationBus.watch('isAvailable', sort);
    TagNotificationBus.watch('dateTimeUpdated', sort);
    TaskNotificationBus.watch('tags', () => ++tagsVersion);

    return $$({
      isLoaded,
      tags,
      tagsAvailable,
      tagIds,
      tagSave,
      tagDelete,
    });
  })();
}
