import { SerializerAsync } from '@vueuse/core';
import { Radix } from '~~/utils/radix';

export class StoreAccessor<T> {
  private radix: Radix<IStore>;

  constructor(store: IStore, private readonly serializer: SerializerAsync<T>) {
    this.radix = new Radix(store);
  }

  async get(key: string): Promise<T | undefined> {
    const data = await this.radix.get<string>(key);
    if (data === undefined) return undefined;
    return await this.serializer.read(data);
  }

  async set(key: string, value: T | undefined) {
    if (value === undefined) {
      await this.del(key);
      return;
    }
    const data = await this.serializer.write(value);
    await this.radix.set(key, data);
  }

  async del(key: string) {
    await this.radix.del(key);
  }
}

export const getSet = useStoreAccessor<Set<string>>(
  new StoreSQLite(import.meta.env.VITE_DATABASE, 'sets'),
  {
    read: async value => {
      const data = JSON.parse(value);
      return new Set(
        Array.isArray(data)
          ? data.filter((d): d is string => typeof d === 'string')
          : [],
      );
    },
    write: data => JSON.stringify([...data]),
  },
  () => new Set(),
);
