import { Awaitable } from '@vueuse/core';
import { UnwrapNestedRefs } from 'vue';
import { Tag } from '~~/models/tag';
import { Task } from '~~/models/task';

const storeSettings = new StoreSQLite(
  import.meta.env.VITE_DATABASE,
  'settings',
);

function useSettings<T>(key: string, factory: () => Awaitable<T>) {
  return useStoreAccessor<T | UnwrapNestedRefs<T & object>>(
    storeSettings,
    {
      read: async value => {
        const data = JSON.parse(value) as T;
        return data && typeof data === 'object' ? reactive(data) : data;
      },
      write: JSON.stringify,
    },
    factory,
  )(key);
}

export async function useStoreSettings() {
  const storeTag = await useStoreTag();
  const storeTask = await useStoreTask();

  const isDarkMode = await useSettings<boolean>(
    'isDarkMode',
    () => window.matchMedia?.('(prefers-color-scheme: dark)').matches ?? false,
  );

  const isRomantic = await useSettings<boolean>('isRomantic', () => true);
  isRomantic.value = !isRomantic.value;
  isRomantic.value = !isRomantic.value;

  return defineStore('settings', () => {
    async function exportBackup() {
      const fileName = `focus-assistant.${Temporal.Now.plainDateTimeISO()
        .toJSON()
        .slice(0, 16)
        .replaceAll(/[^\d_]/g, '')}.json`;
      const tags = storeTag.tags.map(({ data }) => ({ data }));
      const tasks = storeTask.tasks.map(({ data }) => ({ data }));
      const data = JSON.stringify({
        tags,
        tasks,
      });
      const path = await download(`Download/${fileName}`, data);
      await Toast.show({
        text: `Successfully exported ${tags.length} tags and ${
          tasks.length
        } tasks to ${path ?? undefined}`,
        position: 'top',
      });
    }

    async function importBackup(file: File) {
      if (!file) return;
      const [releaseStoreTask, releaseStoreTag] = await Promise.all([
        mutexStoreTask.obtain(),
        mutexStoreTag.obtain(),
      ]);
      try {
        const tagIds = new Set<string>();
        const taskIds = new Set<string>();
        const data = await file.text();
        const { tags = [], tasks = [] } = JSON.parse(data) as {
          tags: Tag[];
          tasks: Task[];
        };
        await Promise.all([
          ...tags.map(async ({ data: { id } }) => {
            tagIds.add(id);
            await storeTag.tagDelete(id, true);
          }),
          ...tasks.map(async ({ data: { id } }) => {
            taskIds.add(id);
            await storeTask.taskDelete(id, true);
          }),
        ]);
        await Promise.all([
          ...tags.map(async ({ data }) => {
            const tag = Tag.fromData(data);
            await storeTag.tagSave(tag, true);
          }, true),
          ...tasks.map(async ({ data }) => {
            const task = Task.fromData(data);
            await storeTask.taskSave(task, true);
          }),
        ]);
        Toast.show({
          text: `Successfully imported ${tagIds.size} tags and ${taskIds.size} tasks`,
          position: 'top',
        });
      } catch (e) {
        console.error(e);
        Toast.show({
          text: `Failed to import tags and tasks`,
          position: 'top',
        });
      } finally {
        releaseStoreTask();
        releaseStoreTag();
      }
    }

    const log = $ref<unknown[]>([]);
    function addLogEntry(entry: unknown) {
      log.push([Temporal.Now.plainTimeISO(), entry]);
    }

    return $$({
      isDarkMode,
      isRomantic,
      export: exportBackup,
      import: importBackup,
      log,
      addLogEntry,
    });
  })();
}
