import { useStoreRomantic } from '~~/stores/storeRomantic';

export default defineNuxtRouteMiddleware(async (_to, _from) => {
  if (Math.random() > 0.1) return;
  const storeRomantic = await useStoreRomantic();
  const lines = [...storeRomantic.lines];
  let line = lines.pop();
  if (line !== undefined) {
    if (line === '') {
      lines.sort(() => Math.random() - 0.5);
      line = lines.pop();
      lines.unshift('');
    }
    if (line !== undefined) {
      lines.unshift(line);
      Toast.show({ text: Base64.decode(line), position: 'center' });
    }
    storeRomantic.lines = new Set(lines);
  }
});
