import { Capacitor } from '@capacitor/core';
import { Toast as CapacitorToast, ShowOptions } from '@capacitor/toast';

const platform = Capacitor.getPlatform();
export const Toast =
  platform === 'web'
    ? {
        async show({ text }: ShowOptions) {
          console.log(text);
          alert(text);
        },
      }
    : CapacitorToast;
