import { UnwrapRef } from 'vue';

export class NotificationBus<
  T extends {
    id: string;
    isDirty: boolean;
    data: { predecessors: string[]; successors: string[] };
    dateTimeUpdated: null | Temporal.PlainDateTime;
  },
  I = T extends { data: infer I } ? I : never,
  Key extends
    | (string & keyof I)
    | (string & keyof T)
    | `${string & keyof I}.status`
    | `recalculate.${string & keyof T}` =
    | (string & keyof I)
    | (string & keyof T)
    | `recalculate.${string & keyof T}`
    | `${string & keyof I}.status`,
> {
  private m_callbacks = {} as Record<Key, Set<(subject: UnwrapRef<T>) => void>>;

  constructor(
    private notify: (
      id: string,
      type: (Key | `predecessor.${Key}` | `successor.${Key}`)[],
    ) => Promise<void>,
  ) {}

  public watch(type: Key, callback: (subject: UnwrapRef<T>) => void) {
    (this.m_callbacks[type] ??= new Set()).add(callback);
  }

  public async emit(subject: UnwrapRef<T>, type?: Key) {
    if (type && type !== 'dateTimeUpdated' && type in subject.data) {
      subject.dateTimeUpdated = Temporal.Now.plainDateTimeISO();
    }
    await this.notify(
      subject.id,
      type ? [type] : (['predecessors', 'successors'] as Key[]),
    );
    type && this.m_callbacks[type]?.forEach(callback => callback(subject));
    if (subject.isDirty) return;
    await Promise.all([
      ...subject.data.successors.map(subjectId =>
        this.notify(subjectId, [
          type ? `predecessor.${type}` : ('predecessors' as Key),
        ]),
      ),
      ...subject.data.predecessors.map(subjectId =>
        this.notify(subjectId, [
          type ? `successor.${type}` : ('successors' as Key),
        ]),
      ),
    ]);
  }
}
