import { DelayedNotificator } from '~~/utils/delayed-notificator';
import { Relations } from '~~/utils/relations';
import { Task } from '~~/models/task';
import { UnwrapRef } from 'vue';

declare global {
  interface ITag {
    id: string;
    name: string;
    predecessors: string[];
    successors: string[];
    tasks: string[];
    dateTimeCreated: null | string;
    dateTimeUpdated: null | string;
    dateStart: null | string;
    timeStart: null | string;
    dateEnd: null | string;
    timeEnd: null | string;
    availability: Frequency;
  }
}

export const TagNotificationBus = new NotificationBus<Tag>(
  async (tagId, types) => {
    const tag = await tagGet(tagId);
    if (!tag) return;

    const actions = [] as Promise<unknown>[];

    if (
      types.some(type =>
        [
          'availability',
          'dateStart',
          'dateEnd',
          'timeStart',
          'timeEnd',
          'predecessors',
          'predecessor.isAvailable',
          'recalculate.isAvailable',
        ].includes(type),
      )
    ) {
      actions.push(tag.refreshIsAvailable());
    }

    if (types.includes('isAvailable')) {
      actions.push(
        Promise.all(
          tag.tasks.map(task => TaskNotificationBus.emit(task, 'tags.status')),
        ),
      );
    }

    await Promise.all(actions);
  },
);

export class Tag {
  public isDirty = false;
  public readonly data: ITag;
  public readonly tasks: Ref<UnwrapRef<Task[]>>;

  private constructor(data: Partial<ITag> = {}) {
    this.data = reactive({
      id: data.id ?? createId(),
      name: `${data.name}`, // TODO: Replace with data.name ?? ''
      predecessors: data.predecessors ?? [],
      successors: data.successors ?? [],
      tasks: data.tasks ?? [],
      dateTimeCreated: data.dateTimeCreated ?? null,
      dateTimeUpdated: data.dateTimeUpdated ?? null,
      dateStart: data.dateStart ?? null,
      timeStart: data.timeStart ?? null,
      dateEnd: data.dateEnd ?? null,
      timeEnd: data.timeEnd ?? null,
      availability: useCloneDeep(data.availability) ?? {
        type: FrequencyType.ALWAYS,
      },
    });

    this.tasks = computedWith(
      [this.data.tasks],
      async () => {
        const storeTask = await useStoreTask();
        let tasks = await Promise.all(this.data.tasks.map(taskGet));
        tasks = tasks.filter(Boolean);
        tasks.sort(
          (a, b) => storeTask.tasks.indexOf(a) - storeTask.tasks.indexOf(b),
        );
        return tasks;
      },
      [],
    );
  }

  public static fromData(data: Partial<ITag>): UnwrapRef<Tag> {
    const tag = reactive(new Tag(data)) as Tag & UnwrapRef<Tag>;
    tag._relations = Relations.create(TagNotificationBus, tag, tagGet);
    tag._notificator = new DelayedNotificator(TagNotificationBus, tag);
    return tag;
  }

  public static create(id?: string) {
    return Tag.fromData({ id, name: '' });
  }

  public static fromTag(tag: Tag) {
    return Tag.fromData(tag.data);
  }

  private _relations!: UnwrapRef<Relations<Tag>>;
  public get relations() {
    return this._relations;
  }

  private _notificator!: DelayedNotificator<Tag>;
  public get notificator() {
    return this._notificator;
  }

  private _isInitialized: symbol | undefined;
  public async init(this: UnwrapRef<Tag>) {
    const tag = this as UnwrapRef<Tag> & Tag;
    if (tag._isInitialized) return;
    tag._isInitialized = Symbol();

    this.isDirty = false;

    this.dateTimeCreated ??= Temporal.Now.plainDateTimeISO();
    this.dateTimeUpdated ??= Temporal.Now.plainDateTimeISO();

    await TagNotificationBus.emit(this);
  }

  public get id() {
    return this.data.id;
  }

  public get name() {
    return this.data.name;
  }
  public set name(value) {
    this.data.name = value;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'name');
  }

  public get dateTimeCreated() {
    return !this.data.dateTimeCreated
      ? null
      : Temporal.PlainDateTime.from(this.data.dateTimeCreated);
  }
  public set dateTimeCreated(value) {
    this.data.dateTimeCreated = value?.toJSON().slice(0, 19) ?? null;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'dateTimeCreated');
  }

  public get dateTimeUpdated() {
    return !this.data.dateTimeUpdated
      ? null
      : Temporal.PlainDateTime.from(this.data.dateTimeUpdated);
  }
  public set dateTimeUpdated(value) {
    this.data.dateTimeUpdated = value?.toJSON().slice(0, 19) ?? null;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'dateTimeUpdated');
  }

  public get dateStart() {
    return !this.data.dateStart
      ? null
      : Temporal.PlainDate.from(this.data.dateStart);
  }
  public set dateStart(value) {
    this.data.dateStart = value?.toJSON().slice(0, 10) ?? null;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'dateStart');
  }

  public get timeStart() {
    return !this.data.timeStart
      ? null
      : Temporal.PlainTime.from(this.data.timeStart);
  }
  public set timeStart(value) {
    this.data.timeStart = value?.toJSON().slice(0, 5) ?? null;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'timeStart');
  }

  public get dateEnd() {
    return !this.data.dateEnd
      ? null
      : Temporal.PlainDate.from(this.data.dateEnd);
  }
  public set dateEnd(value) {
    this.data.dateEnd = value?.toJSON().slice(0, 10) ?? null;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'dateEnd');
  }

  public get timeEnd() {
    return !this.data.timeEnd
      ? null
      : Temporal.PlainTime.from(this.data.timeEnd);
  }
  public set timeEnd(value) {
    this.data.timeEnd = value?.toJSON().slice(0, 5) ?? null;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'timeEnd');
  }

  public get tasksTotal() {
    return this.data.tasks.length;
  }

  public readonly tasksDone: ComputedRef<number> = computed(
    () => this.tasks.value.filter(task => task.isDone).length,
  );

  public get availability() {
    return this.data.availability;
  }
  public set availability(value) {
    this.data.availability = value;
    this.isDirty = true;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'availability');
  }

  private _isAvailable = false;
  public get isAvailable() {
    return this._isAvailable;
  }
  public set isAvailable(value) {
    this._isAvailable = value;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'isAvailable');
  }

  private _tsSwitchAt = Infinity;
  public get tsSwitchAt() {
    return this._tsSwitchAt;
  }
  public set tsSwitchAt(value) {
    this._tsSwitchAt = value;
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'tsSwitchAt');
  }

  public async refreshIsAvailable() {
    const predecessors = await this.relations.predecessors;
    if (predecessors.some(predecessor => !predecessor.isAvailable)) {
      this.isAvailable = false;
      this.tsSwitchAt = Infinity;
      return;
    }

    refreshAvailability(this, () =>
      this.notificator.notify('recalculate.isAvailable', this.tsSwitchAt),
    );
  }

  public taskAdd(this: UnwrapRef<Tag>, task: UnwrapRef<Task>) {
    if (this.data.tasks.indexOf(task.id) > -1) return;
    this.data.tasks.push(task.id);
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'tasks');
    task.tagAdd(this);
  }

  public taskRemove(this: UnwrapRef<Tag>, task: UnwrapRef<Task>) {
    const index = this.data.tasks.indexOf(task.id);
    if (index < 0) return;
    this.data.tasks.splice(index, 1);
    TagNotificationBus.emit(this as UnwrapRef<Tag>, 'tasks');
    task.tagRemove(this);
  }
}

export const useTag = useStoreAccessor<UnwrapRef<Tag>>(
  new StoreSQLite(import.meta.env.VITE_DATABASE, 'tags'),
  {
    read: async value => {
      const { data } = JSON.parse(value) as Tag;
      return Tag.fromData(data);
    },
    write: ({ data }) => JSON.stringify({ data }),
  },
  id => Tag.fromData({ id, name: '⚠️ Failed to fetch from DB' }),
  ({ value: tag }) => tag?.data ?? null,
);

export async function tagGet(id: string): Promise<UnwrapRef<Tag>> {
  return (await useTag(id)).value;
}

export async function tagSet(tag: UnwrapRef<Tag>) {
  (await useTag(tag.id)).value = tag;
}

export async function tagDel(id: string) {
  const refTag = await useTag(id);
  const tag = refTag.value;
  await tag.relations.detach();
  tag.tasks.forEach(task => tag.taskRemove(task));
  refTag.value = undefined as unknown as UnwrapRef<Tag>;
}
