import { UnwrapRef } from 'vue';
import { Task } from '~~/models/task';

export const mutexStoreTask = new Mutex();

export async function useStoreTask() {
  let taskIds = $(await getSet('taskIds'));

  return defineStore('task', () => {
    let isLoaded = $ref(false);
    let tasksVersion = $ref(0);
    let tasks: UnwrapRef<Task>[] = $ref([]);

    const tasksAvailable = $computed(() =>
      tasks.filter(task => task.isAvailable),
    );

    watch(
      $$(tasksVersion),
      async () => {
        const release = await mutexStoreTask.obtain();
        try {
          tasks = await Promise.all([...taskIds].map(taskGet));
          await Promise.all(tasks.map(task => task.init()));
        } finally {
          release();
          isLoaded = true;
        }
      },
      { immediate: true },
    );

    async function taskSave(task: UnwrapRef<Task>, bypass = false) {
      const release = await mutexStoreTask.obtain(bypass);
      try {
        await taskSet(task);
        taskIds.delete(task.id); // Make task appear on the bottom
        taskIds.add(task.id);
        ++tasksVersion;
      } finally {
        release();
      }
    }

    async function taskDelete(taskId: string, bypass = false) {
      const release = await mutexStoreTask.obtain(bypass);
      try {
        taskIds.delete(taskId);
        await taskDel(taskId);
        ++tasksVersion;
      } finally {
        release();
      }
    }

    const dateNeg = Temporal.PlainDateTime.from('1000-01-01');
    async function sort() {
      const release = await mutexStoreTask.obtain();
      try {
        taskIds = new Set(
          tasks
            .sort((a, b) => {
              if (isFinite(a.tsSwitchAt) && isFinite(b.tsSwitchAt)) {
                return (
                  b.tsSwitchAt - a.tsSwitchAt ||
                  Temporal.PlainDateTime.compare(
                    a.dateTimeUpdated ?? dateNeg,
                    b.dateTimeUpdated ?? dateNeg,
                  ) ||
                  +a.isAvailable - +b.isAvailable
                );
              }
              if (isFinite(a.tsSwitchAt)) return 1;
              if (isFinite(b.tsSwitchAt)) return -1;
              return (
                Temporal.PlainDateTime.compare(
                  a.dateTimeUpdated ?? dateNeg,
                  b.dateTimeUpdated ?? dateNeg,
                ) || +a.isAvailable - +b.isAvailable
              );
            })
            .map(task => task.id),
        );

        ++tasksVersion;
      } finally {
        release();
      }
    }

    TaskNotificationBus.watch('tsSwitchAt', sort);
    TaskNotificationBus.watch('isAvailable', sort);
    TaskNotificationBus.watch('dateTimeUpdated', sort);

    return $$({
      isLoaded,
      tasks,
      tasksAvailable,
      taskIds,
      taskSave,
      taskDelete,
    });
  })();
}
