import { Awaitable, SerializerAsync } from '@vueuse/core';
import { Ref, UnwrapRef, WatchStopHandle } from 'vue';
import { StoreAccessor } from '@/utils/store-accessor';

const mutex = new Mutex();
const cacheStoreAccessor = new Map<IStore, StoreAccessor<unknown>>();

export function useStoreAccessor<T>(
  store: IStore,
  serializer: SerializerAsync<T>,
  factory: (key: string) => Awaitable<T>,
  getWatchSource?: (val: Ref<UnwrapRef<T> | undefined>) => object | null,
): (key: string) => Promise<Ref<T>>;
export function useStoreAccessor<T>(
  store: IStore,
  serializer: SerializerAsync<T>,
): (key: string) => Promise<Ref<T | undefined>>;
export function useStoreAccessor<T>(
  store: IStore,
  serializer: SerializerAsync<T>,
  factory?: (key: string) => Awaitable<T>,
  getWatchSource: (val: Ref<UnwrapRef<T> | undefined>) => object | null = val =>
    val,
) {
  const cache = new Map<string, Ref<UnwrapRef<T> | undefined>>();
  return async function (key: string) {
    if (cache.has(key)) return cache.get(key) as T;
    let accessor = cacheStoreAccessor.get(store) as StoreAccessor<T>;
    if (!accessor) {
      accessor = new StoreAccessor<T>(store, serializer);
      cacheStoreAccessor.set(store, accessor);
    }
    const val = ref<T | undefined>(await accessor.get(key));
    if (val.value === undefined && factory) {
      val.value = (await factory(key)) as UnwrapRef<T>;
    }
    let isInitialized = false;
    let isAfterInit = true;
    let stop: WatchStopHandle | null;
    async function setData() {
      if (isAfterInit) {
        isAfterInit = false;
        return;
      }
      const release = await mutex.obtain();
      try {
        await accessor.set(key, val.value as T | undefined);
      } finally {
        release();
      }
    }
    watch(
      val,
      (valNew, valOld) => {
        if (isInitialized && valNew === valOld) return;
        isInitialized = true;
        stop?.();
        if (valNew === undefined) {
          stop = null;
          setData();
          return;
        }
        const watchSource = getWatchSource(val);
        stop = !watchSource
          ? null
          : watch(watchSource, setData, {
              deep: true,
              flush: 'pre',
              immediate: true,
            });
      },
      { deep: false, immediate: true },
    );
    cache.set(key, val);
    return val;
  };
}
