export class Mutex {
  private static releaseStub = () => {
    return;
  };
  private m_lastPromise = Promise.resolve();

  public async obtain(bypass = false) {
    let release = Mutex.releaseStub;
    if (bypass) return release;
    const lastPromise = this.m_lastPromise;
    this.m_lastPromise = new Promise(resolve => release = resolve);
    await lastPromise;
    return release;
  }
}
