import { UnwrapRef } from 'vue';
import { NotificationBus } from '~~/utils/notification-bus';

export class DelayedNotificator<
  T extends {
    id: string;
    isDirty: boolean;
    data: { predecessors: string[]; successors: string[] };
    dateTimeUpdated: null | Temporal.PlainDateTime;
  },
  I = T extends { data: infer I } ? I : never,
  Key extends
    | (string & keyof I)
    | (string & keyof T)
    | `recalculate.${string & keyof T}` =
    | (string & keyof I)
    | (string & keyof T)
    | `recalculate.${string & keyof T}`,
> {
  private m_notifications = new Map<Key, NodeJS.Timeout>();

  constructor(
    private notificationBus: NotificationBus<T, I, Key>,
    private subject: UnwrapRef<T>,
  ) {}

  notify(type: Key, msTimestamp = 0) {
    const msNow = Temporal.Now.instant().epochMilliseconds;
    if (msNow > msTimestamp) return;
    let timeoutId = this.m_notifications.get(type);
    if (timeoutId) clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      this.notificationBus.emit(this.subject, type);
      this.m_notifications.delete(type);
    }, msTimestamp - msNow);
    this.m_notifications.set(type, timeoutId);
  }
}
