export class StoreSQLite implements IStore {
  public constructor(readonly database: string, readonly model: string) {}

  async get<T>(key: string) {
    return await useSQLite(this.database, async db => {
      const { values } = await db.query(
        `SELECT data FROM models WHERE model = ? AND key = ?`,
        [this.model, key],
      );
      if (!values || !values.length) return undefined;
      const [{ data }] = values;
      return JSON.parse(data) as T;
    });
  }

  async set<T>(key: string, value: T) {
    if (value === undefined) {
      await this.del(key);
      return;
    }
    const data = JSON.stringify(value);
    await useSQLite(
      this.database,
      async db =>
        await db.run(
          `INSERT INTO models (model, key, data) VALUES (?, ?, ?) ON CONFLICT(model, key) DO UPDATE SET data = ?`,
          [this.model, key, data, data],
        ),
    );
  }

  async del(key: string) {
    await useSQLite(
      this.database,
      async db =>
        await db.run(`DELETE FROM models WHERE model = ? AND key = ?`, [
          this.model,
          key,
        ]),
    );
  }
}
