import { Mutex } from './mutex';

const RADIX_PREFIX = 'rx';
type RNode = [string, string | [string]][];
let nextId = -1;
const mutex = new Mutex();
export class Radix<TStore extends IStore = IStore> {
  public constructor(public store: TStore) {}

  private nodeSort(node: RNode) {
    return node.sort((a, b) => a[0].localeCompare(b[0]));
  }

  private async nextId() {
    if (nextId < 0) {
      nextId = await this.store.get<number>(`${RADIX_PREFIX}#`) ?? 0;
    }
    const id = nextId.toString(36);
    await this.store.set(`${RADIX_PREFIX}#`, ++nextId);
    return id;
  }

  public async get<T extends JValue>(key: string) {
    const release = await mutex.obtain();
    try {
      let node = await this.store.get<RNode>(RADIX_PREFIX) ?? [];
      let trav = !!node;
      while (trav && node) {
        trav = false;
        for (const [n, v] of node) {
          if (n[0] !== key[0]) continue;
          if (key.slice(0, n.length) === n) {
            key = key.slice(n.length, key.length);
            if (!key && Array.isArray(v)) return JSON.parse(v[0]) as T;
            node = await this.store.get<RNode>(v as string) ?? [];
            trav = true;
            break;
          }
        }
      }
      return undefined;
    } finally {
      release();
    }
  }

  public async set<T extends JValue>(key: string, value: T) {
    const release = await mutex.obtain();
    try {
      const val = [JSON.stringify(value)] as [string];
      let nodePathOld = RADIX_PREFIX;
      let node = await this.store.get<RNode>(nodePathOld) ?? [];
      let traverse = true;
      while (traverse) {
        traverse = false;
        for (let i = 0; i < node.length; ++i) {
          const [k, v] = node[i];
          if (k[0] !== key[0]) continue;
          let kNew = '';
          let kLeft = k;
          while (k && key && kLeft[0] === key[0]) {
            kNew += kLeft.slice(0, 1);
            kLeft = kLeft.slice(1, kLeft.length);
            key = key.slice(1, key.length);
          }
          if (key && !kLeft || k === kNew) {
            if (Array.isArray(v)) {
              if (key === kLeft && !kLeft) {
                node[i] = [k, val];
                await this.store.set(nodePathOld, node);
                return;
              }
            } else {
              nodePathOld = v;
              node = await this.store.get<RNode>(nodePathOld) ?? [];
              traverse = true;
              break;
            }
          }
          const nodePathNew = `${RADIX_PREFIX}_${await this.nextId()}`;
          node.splice(i as unknown as number, 1);
          node.push([kNew, nodePathNew]);
          await this.store.set(nodePathOld, this.nodeSort(node));
          node = [
            [key, val],
            [kLeft, v],
          ];
          await this.store.set(nodePathNew, this.nodeSort(node));
          return;
        }
        if (!traverse && node) {
          node.push([key, val]);
          await this.store.set(nodePathOld, this.nodeSort(node));
          return;
        }
      }
    } finally {
      release();
    }
  }

  public async del(key: string) {
    const release = await mutex.obtain();
    try {
      let curNodePath = RADIX_PREFIX;
      let node = await this.store.get<RNode>(curNodePath);
      if (!node) return false;
      let trav = !!node;
      const prevNodes = [] as [number, string, string, RNode][];
      while (trav && node) {
        trav = false;
        for (let i = 0; i < node.length; ++i) {
          const [n, v] = node[i];
          if (n[0] !== key[0]) continue;
          if (key.slice(0, n.length) === n) {
            key = key.slice(n.length, key.length);
            if (Array.isArray(v)) {
              node.splice(i, 1);
              switch (node.length) {
                case 0: {
                  const prevNode = prevNodes.pop();
                  if (!prevNode) return true;
                  const [curI, , curNodePath] = prevNode;
                  await this.store.del(curNodePath);
                  node = await this.store.get<RNode>(curNodePath);
                  if (!node) return true;
                  node.splice(curI, 1);
                  await this.store.set(curNodePath, node);
                  return true;
                }
                case 1: {
                  await this.store.del(curNodePath);
                  let prevNode = prevNodes.pop();
                  if (!prevNode) return true;
                  const [prevI, prevN] = prevNode;
                  prevNode = prevNodes.pop();
                  if (!prevNode) return true;
                  const nodeOld = node;
                  [, , curNodePath, node] = prevNode;
                  const fieldNew = nodeOld[0];
                  fieldNew[0] = prevN + fieldNew[0];
                  node.splice(prevI, 1, fieldNew);
                  await this.store.set(curNodePath, node);
                  return true;
                }
                default: {
                  await this.store.set(curNodePath, node);
                  return true;
                }
              }
            }
            curNodePath = v as string;
            node = await this.store.get<RNode>(curNodePath);
            node && prevNodes.push([i, n, curNodePath, node]);
            trav = true;
            break;
          }
        }
      }
      return false;
    } finally {
      release();
    }
  }

  private async *_loop<T extends JValue>(
    query: {
      min: undefined | string;
      max: undefined | string;
      pattern: undefined | string;
      count: number;
      sort: 0 | 1;
    },
    key = '',
    root = RADIX_PREFIX,
  ): AsyncGenerator<[string, T], void, unknown> {
    if (!query.count) return;
    const node = await this.store.get<RNode>(root) ?? [];
    for (const i in node) {
      const [k, v] =
        node[query.sort * +i + (1 - query.sort) * (node.length - (+i + 1))];
      const keyAcc = key ? `${key}${k}` : k;
      if (Array.isArray(v)) {
        if (
          query.min && keyAcc < query.min ||
          query.max && keyAcc > query.max ||
          query.pattern &&
            keyAcc.slice(0, query.pattern.length) !== query.pattern
        ) {
          continue;
        }
        yield [keyAcc, JSON.parse(v[0]) as T];
        if (!--query.count) return;
        continue;
      }
      if (
        query.min && keyAcc < query.min.slice(0, keyAcc.length) ||
        query.max && keyAcc > query.max.slice(0, keyAcc.length) ||
        query.pattern &&
          keyAcc.slice(0, query.pattern.length) !==
            query.pattern.slice(0, keyAcc.length)
      ) {
        continue;
      }
      for await (const result of this._loop<T>(query, keyAcc, v)) {
        yield result;
      }
    }
  }

  public async *loop<T extends JValue>(query?: {
    min?: string;
    max?: string;
    pattern?: string;
    count?: number;
    sort?: -1 | 1;
  }): AsyncGenerator<[string, T], void, unknown> {
    const release = await mutex.obtain();
    try {
      for await (const result of this._loop<T>({
        min: query?.min,
        max: query?.max,
        pattern: query?.pattern,
        count: query?.count ?? -1,
        sort: query?.sort === -1 ? 0 : 1,
      })) {
        yield result;
      }
    } finally {
      release();
    }
  }
}
